class Solution:
    def distributeCookies(self, cookies, k):
        n = len(cookies)
        cookies = sorted(cookies, reverse=True)
        totals = [0] * k
        self.best = float('inf')
        def rec(i):
            if i == n:
                self.best = min(self.best, max(totals))
                return
            seen = set()
            for c in range(k):
                if totals[c] in seen:
                    continue
                seen.add(totals[c])
                if totals[c] + cookies[i] >= self.best:
                    continue
                totals[c] += cookies[i]
                rec(i + 1)
                totals[c] -= cookies[i]
        rec(0)
        return self.best

