var distributeCookies = function(cookies, k) {
    const n = cookies.length;
    cookies = cookies.slice().sort((a, b) => b - a);
    const totals = new Array(k).fill(0);
    let best = Infinity;
    const rec = (i) => {
        if (i === n) {
            best = Math.min(best, Math.max(...totals));
            return;
        }
        const seen = new Set();
        for (let c = 0; c < k; c++) {
            if (seen.has(totals[c])) continue;
            seen.add(totals[c]);
            if (totals[c] + cookies[i] >= best) continue;
            totals[c] += cookies[i];
            rec(i + 1);
            totals[c] -= cookies[i];
        }
    };
    rec(0);
    return best;
};
